{
  "grammar": [
    {
      "pattern": "Subject + 天氣 + 很 + Adjective",
      "structure": ["Subject", "天氣", "很", "Adjective"],
      "explanation_en": "Use '很' to describe weather conditions. Unlike English, '很' here is a neutral linking word, not meaning 'very'.",
      "title": "Describing Weather with 很",
      "meaning": "The weather is [adjective]",
      "when_to_use": ["Talking about today's weather", "Answering '天氣怎麼樣？'", "Starting small talk about weather"],
      "when_not_to_use": ["When you want to emphasize 'very' (use 非常 instead)", "With negative forms (use 不 + adjective)"],
      "pragmatic_notes": "In Taiwan, 很 is commonly used even for neutral descriptions. Saying just '天氣熱' sounds abrupt; always add 很 for natural speech.",
      "word_order_notes": "Subject + 天氣 + 很 + Adjective. Do not place 很 after the adjective.",
      "english_contrast": "English says 'The weather is hot' without a degree word. Chinese requires 很 for a complete sentence.",
      "korean_contrast": "Korean uses '날씨가 덥다' without a degree word. Chinese needs 很 to sound natural.",
      "negative_examples": [
        {
          "text": "天氣熱。",
          "error": "Missing 很; sounds incomplete or too direct."
        },
        {
          "text": "天氣很熱很。",
          "error": "很 placed after adjective; wrong word order."
        }
      ],
      "incorrect_examples": [
        {
          "text": "天氣很熱。",
          "error": "Correct sentence; no error."
        },
        {
          "text": "天氣很冷。",
          "error": "Correct sentence; no error."
        }
      ],
      "transformation_drills": ["Change '天氣很熱' to negative: '天氣不熱'", "Change '天氣很冷' to question: '天氣很冷嗎？'"],
      "production_drills": ["Describe today's weather using 很", "Ask a friend about the weather using 很"],
      "common_error_patterns": ["Omitting 很", "Placing 很 after the adjective"],
      "repair_feedback": {
        "word_order": "Remember: Subject + 天氣 + 很 + Adjective.",
        "politeness": "Adding 很 makes the sentence sound polite and natural.",
        "vocabulary": "Use weather adjectives like 熱, 冷, 舒服, 涼快."
      }
    },
    {
      "pattern": "Subject + 有點 + Adjective",
      "structure": ["Subject", "有點", "Adjective"],
      "explanation_en": "Use '有點' to express a slight degree of a feeling or state, often negative or mild.",
      "title": "Expressing Mild Feelings with 有點",
      "meaning": "A little bit [adjective]",
      "when_to_use": ["Describing mild negative feelings", "Softening a complaint", "Talking about slight discomfort"],
      "when_not_to_use": ["For strong emotions (use 很 or 非常)", "For positive feelings (use 有一點 for positive, but less common)"],
      "pragmatic_notes": "In Taiwan, 有點 is very common for politeness. For example, '有點冷' is softer than '很冷'.",
      "word_order_notes": "Subject + 有點 + Adjective. Do not add 很 after 有點.",
      "english_contrast": "English uses 'a little' before adjectives. Chinese uses 有點 before the adjective.",
      "korean_contrast": "Korean uses '조금' before adjectives. Chinese uses 有點 similarly.",
      "negative_examples": [
        {
          "text": "我有點很累。",
          "error": "Cannot use 很 after 有點."
        },
        {
          "text": "我有點累很。",
          "error": "Wrong word order; adjective should come after 有點."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我有點累。",
          "error": "Correct sentence; no error."
        },
        {
          "text": "今天天氣有點冷。",
          "error": "Correct sentence; no error."
        }
      ],
      "transformation_drills": ["Change '我很累' to a milder version using 有點", "Change '我有點緊張' to a stronger version using 很"],
      "production_drills": ["Tell a friend you are a little tired", "Describe the weather as a little cold"],
      "common_error_patterns": ["Adding 很 after 有點", "Using 有點 with strong positive adjectives"],
      "repair_feedback": {
        "word_order": "Place 有點 directly before the adjective.",
        "politeness": "Using 有點 makes your statement softer and more polite.",
        "vocabulary": "Use adjectives like 累, 冷, 熱, 緊張, 不舒服."
      }
    },
    {
      "pattern": "Subject + 太 + Adjective + 了",
      "structure": ["Subject", "太", "Adjective", "了"],
      "explanation_en": "Use '太...了' to express excessiveness or strong degree, often with a negative connotation.",
      "title": "Expressing Excess with 太...了",
      "meaning": "Too [adjective]",
      "when_to_use": ["Complaining about something excessive", "Expressing strong feelings", "Reacting to extreme situations"],
      "when_not_to_use": ["For neutral descriptions (use 很)", "For mild feelings (use 有點)"],
      "pragmatic_notes": "In Taiwan, 太...了 is common for complaints. For example, '太貴了' means 'too expensive'. Can also be positive: '太好了' means 'great'.",
      "word_order_notes": "Subject + 太 + Adjective + 了. The 了 is mandatory at the end.",
      "english_contrast": "English uses 'too' before adjectives. Chinese uses 太 before and 了 after.",
      "korean_contrast": "Korean uses '너무' before adjectives. Chinese uses 太...了 structure.",
      "negative_examples": [
        {
          "text": "今天太熱。",
          "error": "Missing 了 at the end."
        },
        {
          "text": "今天太了熱。",
          "error": "Wrong word order; 了 must be at the end."
        }
      ],
      "incorrect_examples": [
        {
          "text": "今天太熱了。",
          "error": "Correct sentence; no error."
        },
        {
          "text": "這個太貴了。",
          "error": "Correct sentence; no error."
        }
      ],
      "transformation_drills": ["Change '今天很熱' to express 'too hot'", "Change '這個很貴' to express 'too expensive'"],
      "production_drills": ["Complain that the weather is too hot", "Say that a price is too expensive"],
      "common_error_patterns": ["Omitting 了", "Placing 了 in the wrong position"],
      "repair_feedback": {
        "word_order": "Remember: Subject + 太 + Adjective + 了.",
        "politeness": "Using 太...了 can sound strong; use carefully in polite contexts.",
        "vocabulary": "Use adjectives like 熱, 冷, 貴, 大, 小, 好."
      }
    }
  ]
}
